/* Custom Logger v0.0.1
 * ====================================================================== */

const isBrowser = (
  typeof window !== 'undefined' && typeof window.document !== 'undefined'
);

console.success = function(args) {
  const data = {
    greenBg: isBrowser ? 'background-color: #0F9D58;' : '\x1b[42m',
    greenFg: isBrowser ? 'color: #0F9D58;' : '\x1b[32m',
    whiteFg: isBrowser ? 'color: white;' : '\x1b[37m',
    reset: isBrowser ? '' : '\x1b[0m',
  };

  if (isBrowser) {
    console.log(`%c%c${args}`, `${data.greenBg} ${data.whiteFg}`, data.greenFg);
  } else {
    console.log(
        data.greenBg + data.whiteFg,
        data.icon,
        data.reset,
        data.greenFg,
        ...arguments,
        data.reset,
    );
  }
};

/* Generate User ID v0.0.1
 * ====================================================================== */

function generateUserID() {
  let userID = localStorage.getItem('user-id');
  if (userID != null) {
    return userID;
  }

  try {
    userID = crypto.randomUUID();
  }
  catch(error) {
    userID = ([1e7]+-1e3+-4e3+-8e3+-1e11).replace(/[018]/g, c =>
      (c ^ crypto.getRandomValues(new Uint8Array(1))[0] & 15 >> c / 4).toString(16)
    )
  }

  localStorage.setItem('user-id', userID);
  return userID;
}

function isNum(n) { return /^\d+$/.test(n); }

function convertToSpreadsheetObject(obj) {
  const res = {}
  let k = Object.keys(obj)
  // for (const row in obj) {
  for (const [row, value] of Object.entries(obj)){
    // console.log(row, value);
    if (! isNum(row)) {
      res[row] = value;
      continue;
    }
    const rowIdx = parseInt(row);
    res[rowIdx] = {"cells": {}};
    for (const col in obj[rowIdx]["cells"]) {
      const colIdx = parseInt(col);
      res[rowIdx]["cells"][colIdx] = {"text": String(obj[rowIdx]["cells"][colIdx])};
    }
  }

  // console.log(res);
  return res;
}

